import numpy as np

def cosine_distance(array1, array2):
    dot_product = np.dot(array1, array2)
    norm_a = np.linalg.norm(array1)
    norm_b = np.linalg.norm(array2)
    return 1.0 - (dot_product / (norm_a * norm_b))

